{"type": "email", "id": "email_001", "subject": "Weekly IT Operations Team Meeting", "from": "emily.patel@mediconnsolutions.com", "from_name": "Emily Patel", "to": ["james.harrison@mediconnsolutions.com", "susan.martin@mediconnsolutions.com", "robert.miller@mediconnsolutions.com"], "cc": [], "date": "2023-02-17 08:30:00", "body": "Good Morning Team,

